{
  "name": "youtube_comment_analysis",
  "description": "Analyzes YouTube comments to identify what viewers like, dislike, and are asking for.",
  "type": "object",
  "properties": {
    "doing_well": {
      "type": "array",
      "description": "A list of key things the channel is doing well, based on positive viewer feedback.",
      "items": {
        "type": "string"
      }
    },
    "audience_dislikes": {
      "type": "array",
      "description": "A list of recurring issues or criticisms mentioned by the audience.",
      "items": {
        "type": "string"
      }
    },
    "audience_requests": {
      "type": "array",
      "description": "A list of things viewers are asking for or want to see in future content.",
      "items": {
        "type": "string"
      }
    }
  },
  "required": ["doing_well", "audience_dislikes", "audience_requests"]
}

{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "Jason YouTube Title Ideas Output",
  "type": "object",
  "additionalProperties": false,
  "required": ["title_ideas"],
  "properties": {
    "title_ideas": {
      "type": "array",
      "description": "Exactly 3 original, high-potential ideas generated by cross-referencing Get Competitor Data and Get My Channel Data.",
      "minItems": 3,
      "maxItems": 3,
      "items": {
        "type": "object",
        "additionalProperties": false,
        "required": [
          "title",
          "inspiration_video",
          "thumbnail_idea",
          "script_outline"
        ],
        "properties": {
          "title": {
            "type": "string",
            "minLength": 1,
            "description": "Proposed video title."
          },
          "inspiration_video": {
            "type": "string",
            "format": "uri",
            "pattern": "^(https?):\\/\\/[\\w.-]+(\\/[\\w\\-./?%&=+#]*)?$",
            "description": "URL to a relevant video from the collected dataset (competitor or adjacent niche). Must exist in the data results."
          },
          "thumbnail_idea": {
            "type": "string",
            "minLength": 1,
            "description": "Concrete thumbnail concept."
          },
          "script_outline": {
            "type": "string",
            "minLength": 1,
            "description": "Very short outline (3–5 beats; e.g., Hook → Value → Proof → CTA)."
          }
        }
      }
    }
  }
}

