// n8n Code node
const raw = $json.output || '';            // agent output
const max = 2400;                          // stay safely under Slack block quirks
let msg = raw.replace(/\n{3,}/g, '\n\n');  // de-chunk
if (msg.length > max) {
  msg = msg.slice(0, max - 3) + '...';
}
return [{ json: { text: msg } }];

// Get the input from the previous node
const items = $input.all();

// Simple Markdown to Slack mrkdwn converter
function convertMarkdownToSlackMrkdwn(text) {
    // 1. Convert headers to bold
    text = text.replace(/^#{1,6}\s+(.+)$/gm, '*$1*');

    // 2. Convert links [text](url) to <url|text>
    text = text.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<$2|$1>');

    // 3. Convert bold **text** to *text*
    text = text.replace(/\*\*([^*]+)\*\*/g, '*$1*');

    // 4. Convert italic *text* to _text_ (but not list items)
    text = text.replace(/(?<!^|\n)\*([^*\n]+)\*/g, '_$1_');

    // 5. Convert strikethrough ~~text~~ to ~text~
    text = text.replace(/~~([^~]+)~~/g, '~$1~');

    // Code blocks and inline code are already compatible
    // Lists are already compatible

    return text;
}

// Process each item
return items.map(item => {
    // Get the text content from the input
    const originalText = item.json.output || item.json.text || item.json.content || '';

    // Convert to Slack mrkdwn
    const slackFormatted = convertMarkdownToSlackMrkdwn(originalText);

    // Return the formatted output
    return {
        json: {
            ...item.json,
            slackFormatted: slackFormatted,
            originalText: originalText
        }
    };
});
